#include <bits/stdc++.h>
using namespace std;
const int maxn=1e8+5;
int p[maxn],mark[maxn];
int main(){
    int n,q,cnt=0;
    cin>>n>>q;
    for(int i=2;i<=n;i++){
        if(!mark[i])
            p[++cnt]=i;
        for(int j=1;j<=cnt;j++){
            if(i*p[j]>n)
                break;
            mark[i*p[j]]=1;
            if(i%p[j]==0)
                break;
        }
    }
    while(q--){
        int k;
        cin>>k;
        cout<<p[k]<<'\n';
    }
    return 0;
}
